patch:
--- a/adder_64bit.v
+++ b/adder_64bit.v
@@ -6,7 +6,7 @@
    output reg [64:0] sum_out
  );

-  always @(operand_a) begin
+  always @(operand_a or operand_b or carry_in) begin
     sum_out = operand_a + operand_b + {64'h0, carry_in};
   end

before_code:
module adder_64bit (
  input [63:0] operand_a,
  input [63:0] operand_b,
  input carry_in,
  output reg [64:0] sum_out
);

  always @(operand_a) begin
    sum_out = operand_a + operand_b + {64'h0, carry_in};
  end

endmodule

after_code:
module adder_64bit (
  input [63:0] operand_a,
  input [63:0] operand_b,
  input carry_in,
  output reg [64:0] sum_out
);

  always @(operand_a or operand_b or carry_in) begin
    sum_out = operand_a + operand_b + {64'h0, carry_in};
  end

endmodule
